UPDATE public.questions SET
  stimulus_text = 'A scientist is researching the use of external stimuli to reduce the itching sensation caused by an allergic histamine response.  She finds that while harmless applications of vibration or warming can provide a temporary distraction, such innocuous stimuli actually offer less relief than a stimulus that seems less benign, like a mild electric shock.  Which of the following is the most likely reason why the scientist uses the word "innocuous" in this context?',
  question_text = 'The word "innocuous" is used most likely to',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"emphasize the temporary nature of the relief provided by vibration or warming.","is_correct":false,"explanation":"Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"highlight the contrast between stimuli that are perceived as harmless and those that seem less benign.","is_correct":true,"explanation":"Choice B matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"describe the specific effects of vibration and warming on itching sensation.","is_correct":false,"explanation":"Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"suggest that the scientist is not recommending vibration or warming as effective treatments.","is_correct":false,"explanation":"Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'B',
  explanation = 'The scientist uses the word "innocuous" to highlight the contrast between stimuli that are perceived as harmless (vibration and warming) and those that seem less benign (a mild electric shock). This contrast is important to the scientist’s overall argument about the effectiveness of different stimuli in reducing itching sensation. The passage states that "A scientist is researching the use of external stimuli to reduce the itching sensation caused by an allergic histamine r…", which is the textual anchor for eliminating weaker choices. Choice B is correct because it aligns with that evidence: highlight the contrast between stimuli that are perceived as harmless and those that seem less benig…. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
